const express = require('express');
const http = require('http');
const socketio = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketio(server);

const players = new Map();
const sessions = new Map();
const leaderboard = [];

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

function authenticatePlayer(username, password) {
  if (!username || username.length < 3) {
    return { success: false, message: 'Username must be at least 3 characters' };
  }
  
  const sessionToken = generateSessionToken();
  const playerId = crypto.createHash('md5').update(username).digest('hex');
  
  const playerData = {
    id: playerId,
    username: username,
    score: 0,
    sessionToken: sessionToken,
    connectedAt: Date.now(),
    lastActivity: Date.now()
  };
  
  players.set(playerId, playerData);
  sessions.set(sessionToken, playerId);
  
  return {
    success: true,
    sessionToken: sessionToken,
    playerId: playerId,
    username: username
  };
}

function validateSession(sessionToken) {
  const playerId = sessions.get(sessionToken);
  if (!playerId) {
    return null;
  }
  
  const player = players.get(playerId);
  if (player) {
    player.lastActivity = Date.now();
    return player;
  }
  
  return null;
}

function updateLeaderboard(playerId, username, score) {
  const existingIndex = leaderboard.findIndex(entry => entry.playerId === playerId);
  
  if (existingIndex !== -1) {
    leaderboard[existingIndex].score = score;
    leaderboard[existingIndex].username = username;
  } else {
    leaderboard.push({
      playerId: playerId,
      username: username,
      score: score,
      timestamp: Date.now()
    });
  }
  
  leaderboard.sort((a, b) => b.score - a.score);
  
  return leaderboard.slice(0, 100);
}

io.on('connection', (socket) => {
  console.log('New connection:', socket.id);
  
  let currentPlayer = null;
  
  socket.on('authenticate', (data) => {
    const { username, password } = data;
    const authResult = authenticatePlayer(username, password);
    
    if (authResult.success) {
      currentPlayer = players.get(authResult.playerId);
      socket.emit('authenticated', {
        success: true,
        sessionToken: authResult.sessionToken,
        playerId: authResult.playerId,
        username: authResult.username,
        score: currentPlayer.score
      });
      
      console.log(`Player authenticated: ${username} (${authResult.playerId})`);
    } else {
      socket.emit('authenticated', {
        success: false,
        message: authResult.message
      });
    }
  });
  
  socket.on('login', (data) => {
    const { sessionToken } = data;
    const player = validateSession(sessionToken);
    
    if (player) {
      currentPlayer = player;
      socket.emit('login_success', {
        success: true,
        playerId: player.id,
        username: player.username,
        score: player.score
      });
      
      console.log(`Player logged in: ${player.username}`);
    } else {
      socket.emit('login_success', {
        success: false,
        message: 'Invalid session token'
      });
    }
  });
  
  socket.on('submit_score', (data) => {
    const { sessionToken, score, username } = data;
    
    const player = validateSession(sessionToken);
    
    if (player) {
      player.score = score;
      player.username = username || player.username;
      
      const updatedLeaderboard = updateLeaderboard(player.id, player.username, score);
      
      socket.emit('score_accepted', {
        success: true,
        score: score,
        username: player.username,
        playerId: player.id
      });
      
      io.emit('leaderboard_update', {
        leaderboard: updatedLeaderboard
      });
      
      console.log(`Score submitted: ${player.username} - ${score}`);
    } else {
      socket.emit('score_accepted', {
        success: false,
        message: 'Invalid session'
      });
    }
  });
  
  socket.on('update_score', (data) => {
    const { sessionToken, score } = data;
    
    const player = validateSession(sessionToken);
    
    if (player) {
      player.score = score;
      
      socket.emit('score_updated', {
        success: true,
        score: score
      });
      
      console.log(`Score updated: ${player.username} - ${score}`);
    }
  });
  
  socket.on('get_leaderboard', () => {
    socket.emit('leaderboard', {
      leaderboard: leaderboard.slice(0, 100)
    });
  });
  
  socket.on('player_move', (data) => {
    const { sessionToken, move, position, action } = data;
    
    const player = validateSession(sessionToken);
    
    if (player) {
      io.emit('player_moved', {
        playerId: player.id,
        username: player.username,
        move: move,
        position: position,
        action: action
      });
    }
  });
  
  socket.on('game_action', (data) => {
    const { sessionToken, action, value } = data;
    
    const player = validateSession(sessionToken);
    
    if (player) {
      io.emit('player_action', {
        playerId: player.id,
        username: player.username,
        action: action,
        value: value
      });
    }
  });
  
  socket.on('disconnect', () => {
    if (currentPlayer) {
      console.log(`Player disconnected: ${currentPlayer.username}`);
    } else {
      console.log('Connection closed:', socket.id);
    }
  });
});

app.use(express.json());
app.use(express.static('public'));

app.get('/api/leaderboard', (req, res) => {
  res.json({
    success: true,
    leaderboard: leaderboard.slice(0, 100)
  });
});

app.get('/api/player/:playerId', (req, res) => {
  const player = players.get(req.params.playerId);
  
  if (player) {
    res.json({
      success: true,
      player: {
        id: player.id,
        username: player.username,
        score: player.score
      }
    });
  } else {
    res.status(404).json({
      success: false,
      message: 'Player not found'
    });
  }
});

const PORT = process.env.PORT || 3000;

server.listen(PORT, () => {
  console.log(`Game server running on port ${PORT}`);
});